private val ALLOWED_CAPTURE_EXTENSIONS = setOf("pcap", "pcapng", "log", "txt")

private fun isAllowedCaptureFile(pathOrName: String): Boolean {
    val clean = pathOrName.substringAfterLast('/').substringAfterLast('\\')
    val ext = clean.substringAfterLast('.', "").lowercase(Locale.US)
    return ext in ALLOWED_CAPTURE_EXTENSIONS
}

@Composable
@OptIn(kotlinx.coroutines.FlowPreview::class)
fun ExportScreen(repo: CydRepository) {
    val context = LocalContext.current
    val settings = remember { SettingsStore(context) }
    val vault = remember { VaultManager(context) }
    val scope = rememberCoroutineScope()

    val connection by repo.connection.collectAsState()
    val files by repo.currentFiles.collectAsState()
    var currentPath by remember { mutableStateOf("/sd") }
    val atRoot = currentPath == "/" || currentPath == "/sd" || currentPath == "/lfs"

    val projectId by settings.vaultProjectId.collectAsState(initial = "default")
    val activeCaptureId by settings.vaultCaptureId.collectAsState(initial = null)
    val activeCaptureLabel by settings.vaultCaptureLabel.collectAsState(initial = null)

    var projectInput by remember { mutableStateOf(projectId) }
    LaunchedEffect(projectId) {
        projectInput = projectId
    }
    LaunchedEffect(Unit) {
        snapshotFlow { projectInput }
            .debounce(350)
            .distinctUntilChanged()
            .collect { settings.setVaultProjectId(it) }
    }

    var vaultStatus by remember { mutableStateOf("") }
    var isPulling by remember { mutableStateOf(false) }
    var pullProgress by remember { mutableStateOf("") }
    var pullFraction by remember { mutableStateOf(0f) }
    var currentFileExpectedBytes by remember { mutableStateOf(0L) }
    var totalExpectedBytes by remember { mutableStateOf(0L) }
    var transferredBytes by remember { mutableStateOf(0L) }
    var transferredFiles by remember { mutableStateOf(0) }
    var failedFiles by remember { mutableStateOf(0) }
    val transferLog = remember { mutableStateListOf<String>() }
    val transferLogListState = rememberLazyListState()
    var showBookmarkDialog by remember { mutableStateOf(false) }
    var bookmarkUrl by remember { mutableStateOf("") }
    var bookmarkTitle by remember { mutableStateOf("") }

    suspend fun getOrCreateCaptureId(source: String, label: String = source): String {
        val existing = activeCaptureId
        if (!existing.isNullOrBlank()) return existing

        val created = vault.createCapture(projectId = projectId, label = label, source = source)
        settings.setVaultCaptureId(created.captureId)
        settings.setVaultCaptureLabel(created.label)
        val capPath = vault.getCapturePath(projectId, created.captureId).absolutePath
        vaultStatus = "✓ Active capture: ${created.label}\n$capPath"
        return created.captureId
    }

    val importFolderLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenDocumentTree()
    ) { uri: Uri? ->
        if (uri == null) return@rememberLauncherForActivityResult
        scope.launch {
            val capId = getOrCreateCaptureId(source = "PHONE_SD", label = "PHONE_SD")
            try {
                // Persist permission so the user doesn't need to re-consent each time for this tree.
                context.contentResolver.takePersistableUriPermission(
                    uri,
                    android.content.Intent.FLAG_GRANT_READ_URI_PERMISSION
                )
            } catch (_: Exception) {
                // Best-effort; some providers do not allow persistable permissions.
            }
            val count = vault.importDocumentTree(projectId, capId, uri)
            val capPath = vault.getCapturePath(projectId, capId).absolutePath
            vaultStatus = "✓ Imported folder into vault ($count allowed file(s): .pcap .pcapng .log .txt)\n$capPath"
        }
    }

    val importMediaLauncher = rememberLauncherForActivityResult(
        contract = ActivityResultContracts.OpenMultipleDocuments()
    ) { uris: List<Uri> ->
        if (uris.isEmpty()) return@rememberLauncherForActivityResult
        scope.launch {
            val capId = getOrCreateCaptureId(source = "PHONE_MEDIA", label = "PHONE_MEDIA")
            val out = vault.importUris(projectId, capId, uris)
            val skipped = (uris.size - out.size).coerceAtLeast(0)
            val capPath = vault.getCapturePath(projectId, capId).absolutePath
            vaultStatus = "✓ Imported ${out.size} allowed file(s) into vault" +
                if (skipped > 0) "\nSkipped $skipped unsupported file(s)" else "" +
                "\n$capPath"
        }
    }

    suspend fun pullCurrentFolderToVault(recursive: Boolean = false) {
        if (isPulling) return
        
        // Check connection first
        if (connection.status != ConnectionState.Status.CONNECTED) {
            vaultStatus = "✗ CYD not connected. Go to LIVE tab first."
            return
        }
        
        isPulling = true
        pullProgress = "Initializing..."
        pullFraction = 0f
        currentFileExpectedBytes = 0L
        totalExpectedBytes = 0L
        transferredBytes = 0L
        transferredFiles = 0
        failedFiles = 0
        transferLog.clear()
        vaultStatus = "⟳ Starting pull from CYD..."
        
        try {
            val cap = getOrCreateCaptureId(source = "CYD:${currentPath}", label = currentPath)
            
            val allFiles = if (recursive) {
                // Use recursive listing to get all files including subfolders
                repo.listFilesRecursive(currentPath).filter { !it.isDirectory }
            } else {
                files.filter { !it.isDirectory }
            }
            val filesToPull = allFiles.filter { isAllowedCaptureFile(it.path.ifBlank { it.name }) }
            val skippedByType = allFiles.size - filesToPull.size
            
            if (filesToPull.isEmpty()) {
                vaultStatus = if (allFiles.isEmpty()) {
                    "⚠ No files found in $currentPath (or list API returned none)"
                } else {
                    "⚠ No allowed files in $currentPath. Allowed: .pcap .pcapng .log .txt"
                }
                isPulling = false
                pullProgress = ""
                pullFraction = 0f
                return
            }

            var ok = 0
            val total = filesToPull.size
            totalExpectedBytes = filesToPull.sumOf { it.size.coerceAtLeast(0L) }
            val basePath = currentPath.trimEnd('/')
            val startMs = System.currentTimeMillis()
            vaultStatus = "⟳ Found $total allowed file(s), downloading..." +
                if (skippedByType > 0) " (skipped $skippedByType unsupported)" else ""

            // Tell the CYD to show a visual indicator while we pull from SD.
            runCatching { repo.setCompanionSync(true) }
            
            for ((idx, f) in filesToPull.withIndex()) {
                // Extract relative subPath
                val relativePath = f.path.removePrefix(basePath).trimStart('/')
                val subPath = relativePath.substringBeforeLast('/', "")
                val displayName = if (subPath.isNotEmpty()) "$subPath/${f.name}" else f.name
                currentFileExpectedBytes = f.size.coerceAtLeast(0L)
                
                pullProgress = "Downloading ${idx + 1}/$total: $displayName"
                pullFraction = if (totalExpectedBytes > 0L) {
                    (transferredBytes.toFloat() / totalExpectedBytes.toFloat()).coerceIn(0f, 1f)
                } else {
                    (idx.toFloat() / total.toFloat()).coerceIn(0f, 1f)
                }
                val bytes = withContext(Dispatchers.IO) { repo.downloadFileBytes(f) }
                if (bytes == null) {
                    failedFiles++
                    transferLog.add("✗ ${idx + 1}/$total  $displayName")
                    pullProgress = "Failed: $displayName"
                    kotlinx.coroutines.delay(800)
                    continue
                }
                withContext(Dispatchers.IO) {
                    vault.saveBytes(projectId, cap, f.name, bytes, subPath = subPath)
                }
                ok++
                transferredFiles = ok
                transferredBytes += bytes.size.toLong()
                pullFraction = if (totalExpectedBytes > 0L) {
                    (transferredBytes.toFloat() / totalExpectedBytes.toFloat()).coerceIn(0f, 1f)
                } else {
                    ((idx + 1).toFloat() / total.toFloat()).coerceIn(0f, 1f)
                }
                transferLog.add("✓ ${idx + 1}/$total  $displayName  (${formatBytes(bytes.size.toLong())})")
                if (transferLog.size > 120) {
                    transferLog.removeRange(0, transferLog.size - 120)
                }
            }
            currentFileExpectedBytes = 0L
            pullFraction = 1f
            val elapsed = (System.currentTimeMillis() - startMs).coerceAtLeast(1L)
            val speed = (transferredBytes.toDouble() / (elapsed / 1000.0)).toLong()
            val capPath = vault.getCapturePath(projectId, cap).absolutePath
            vaultStatus = "✓ Pulled $ok/$total allowed file(s) in ${elapsed / 1000.0}s\n${formatBytes(transferredBytes)} total" +
                "\nAvg speed ${formatBytes(speed)}/s" +
                if (skippedByType > 0) "\nSkipped $skippedByType unsupported file(s)\n$capPath" else "\n$capPath"
            pullProgress = ""
        } catch (e: Exception) {
            vaultStatus = "✗ Pull failed: ${e.message}"
            pullProgress = ""
            pullFraction = 0f
            currentFileExpectedBytes = 0L
            totalExpectedBytes = 0L
        } finally {
            runCatching { repo.setCompanionSync(false) }
            isPulling = false
        }
    }

    LaunchedEffect(currentPath) {
        repo.listFiles(currentPath)
    }

    if (showBookmarkDialog) {
        AlertDialog(
            onDismissRequest = { showBookmarkDialog = false },
            title = { Text("Add Bookmark to Vault") },
            text = {
                Column(Modifier.fillMaxWidth(), verticalArrangement = Arrangement.spacedBy(10.dp)) {
