private fun formatBytes(bytes: Long): String {
    if (bytes < 1024) return "$bytes B"
    val kb = bytes / 1024.0
    if (kb < 1024) return "${(kb * 10.0).roundToInt() / 10.0} KB"
    val mb = kb / 1024.0
    if (mb < 1024) return "${(mb * 10.0).roundToInt() / 10.0} MB"
    val gb = mb / 1024.0
    return "${(gb * 10.0).roundToInt() / 10.0} GB"
}

@Composable
fun FileItem(file: CydFile, onFolderClick: (CydFile) -> Unit, onDownloadClick: (CydFile) -> Unit) {
    ListItem(
        modifier = Modifier.clickable { if (file.isDirectory) onFolderClick(file) },
        headlineContent = { Text(file.name) },
        supportingContent = {
            if (!file.isDirectory) {
                Text("${file.size} bytes")
            }
        },
        leadingContent = {
            Icon(
                if (file.isDirectory) Icons.Default.Folder else Icons.AutoMirrored.Filled.InsertDriveFile,
                contentDescription = null,
                tint = if (file.isDirectory) MaterialTheme.colorScheme.primary else Color.Gray
            )
        },
        trailingContent = {
            if (!file.isDirectory) {
                IconButton(onClick = { onDownloadClick(file) }) {
                    Icon(Icons.Default.Download, contentDescription = "Download", tint = MaterialTheme.colorScheme.secondary)
                }
            }
        },
        colors = ListItemDefaults.colors(containerColor = Color.Transparent)
    )
}
